using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    private static readonly Dictionary<string, string> AppConfig = new()
    {
        ["Environment"] = "Production",
        ["MaxRetries"] = "3",
        ["TimeoutSeconds"] = "30",
        ["FeatureFlags.DarkMode"] = "true",
        ["FeatureFlags.BetaAccess"] = "false"
    };

    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns the full application configuration as JSON.")]
    public static string GetAllSettings() =>
        JsonSerializer.Serialize(AppConfig, new JsonSerializerOptions { WriteIndented = true });

    [McpServerResource(
        UriTemplate = "config://app/settings/{key}",
        Name = "App Setting by Key",
        MimeType = "text/plain"),
     Description("Returns a single configuration value by key.")]
    public static string GetSetting(string key) =>
        AppConfig.TryGetValue(key, out var value) ? value : $"Key '{key}' not found";
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Lists all available configuration keys.")]
    public static string ListKeys()
    {
        var keys = new[] { "Environment", "MaxRetries", "TimeoutSeconds",
                           "FeatureFlags.DarkMode", "FeatureFlags.BetaAccess" };
        return JsonSerializer.Serialize(keys);
    }

    [McpServerTool, Description("Validates whether a configuration key exists and its value is non-empty.")]
    public static string ValidateKey(
        [Description("The configuration key to validate")] string key)
    {
        var knownKeys = new Dictionary<string, string>
        {
            ["Environment"] = "Production",
            ["MaxRetries"] = "3",
            ["TimeoutSeconds"] = "30",
            ["FeatureFlags.DarkMode"] = "true",
            ["FeatureFlags.BetaAccess"] = "false"
        };

        if (!knownKeys.TryGetValue(key, out var value))
            return $"INVALID: Key '{key}' does not exist.";

        return string.IsNullOrWhiteSpace(value)
            ? $"WARNING: Key '{key}' exists but has an empty value."
            : $"OK: Key '{key}' = '{value}'";
    }
}

