+[McpServerToolType]
+public static class ConfigTools
+{
+    [McpServerTool, Description("Lists all available configuration keys.")]
+    public static string ListKeys()
+    {
+        var keys = new[] { "Environment", "MaxRetries", "TimeoutSeconds",
+                           "FeatureFlags.DarkMode", "FeatureFlags.BetaAccess" };
+        return JsonSerializer.Serialize(keys);
+    }
+
+    [McpServerTool, Description("Validates whether a configuration key exists and its value is non-empty.")]
+    public static string ValidateKey(
+        [Description("The configuration key to validate")] string key)
+    {
+        var knownKeys = new Dictionary<string, string>
+        {
+            ["Environment"] = "Production",
+            ["MaxRetries"] = "3",
+            ["TimeoutSeconds"] = "30",
+            ["FeatureFlags.DarkMode"] = "true",
+            ["FeatureFlags.BetaAccess"] = "false"
+        };
+
+        if (!knownKeys.TryGetValue(key, out var value))
+            return $"INVALID: Key '{key}' does not exist.";
+
+        return string.IsNullOrWhiteSpace(value)
+            ? $"WARNING: Key '{key}' exists but has an empty value."
+            : $"OK: Key '{key}' = '{value}'";
+    }
+}
+
